graphql.query:
query GetProductConfigurableDetails($sku: String!) {
  products(filter: { sku: { eq: $sku } }) {
    items {
      sku
      name
      type_id
      ... on ConfigurableProduct {
        configurable_options {
          attribute_code
          attribute_id
          label
          values {
            value_index
            label
          }
        }
      }
    }
  }
}

mutation AddProductsToCart($cartId: String!, $cartItems: [CartItemInput!]!) {
  addProductsToCart(cartId: $cartId, cartItems: $cartItems) {
    cart {
      id
      items {
        id
        quantity
        product {
          sku
          name
        }
        prices {
          price {
            value
            currency
          }
        }
      }
    }
  }
}

mutation DeleteProjectImage($imageUuid: String!) {
  deleteImageEditorProjectImage(imageUuid: $imageUuid) {
    imageUuid
    success
  }
}

mutation DeleteProject($uuid: String!) {
  deleteImageEditorProject(uuid: $uuid) {
    uuid
    success
  }
}
